### Scissor Stack

```rust
impl Buffer {
    /// Push a new scissor rectangle (intersected with current).
    ///
    /// All subsequent writes are clipped to this intersection.
    /// Call `pop_scissor()` to restore previous scissor.
    pub fn push_scissor(&mut self, rect: Rect) {
        let current = self.current_scissor();
        let intersection = current.intersection(&rect);
        self.scissor_stack.push(intersection);
        trace!(
            ?current, ?rect, ?intersection,
            stack_depth = self.scissor_stack.len(),
            "Pushed scissor"
        );
    }

    /// Pop the top scissor rectangle.
    ///
    /// Base scissor (full buffer) cannot be popped.
    pub fn pop_scissor(&mut self) {
        if self.scissor_stack.len() > 1 {
            self.scissor_stack.pop();
            trace!(stack_depth = self.scissor_stack.len(), "Popped scissor");
        } else {
            debug!("Attempted to pop base scissor, ignored");
        }
    }

    /// Get current effective scissor rectangle.
    #[inline]
    pub fn current_scissor(&self) -> Rect {
        *self.scissor_stack.last().unwrap() // Invariant: always ≥1 element
    }

    /// Check if point is within current scissor.
    #[inline]
    fn in_scissor(&self, x: u16, y: u16) -> bool {
        self.current_scissor().contains(x, y)
    }

    /// RAII guard for scissor scope.
    pub fn scissor_scope(&mut self, rect: Rect) -> ScissorGuard<'_> {
        self.push_scissor(rect);
        ScissorGuard { buffer: self }
    }
}

/// RAII guard that pops scissor on drop.
pub struct ScissorGuard<'a> {
    buffer: &'a mut Buffer,
}

impl Drop for ScissorGuard<'_> {
    fn drop(&mut self) {
        self.buffer.pop_scissor();
    }
}
