#[cfg(test)]
mod tests {
    use super::*;
    use tracing_test::traced_test;

    // --- Construction ---

    #[traced_test]
    #[test]
    fn test_new_creates_correct_size() {
        let buf = Buffer::new(80, 24);
        assert_eq!(buf.width(), 80);
        assert_eq!(buf.height(), 24);
        assert_eq!(buf.cells().len(), 80 * 24);
        assert!(logs_contain("Creating Buffer"));
    }

    #[test]
    fn test_all_cells_default() {
        let buf = Buffer::new(10, 10);
        for cell in buf.cells() {
            assert_eq!(*cell, Cell::default());
        }
    }

    // --- Bounds checking ---

    #[test]
    fn test_get_returns_none_for_oob() {
        let buf = Buffer::new(10, 10);
        assert!(buf.get(10, 0).is_none()); // x out of bounds
        assert!(buf.get(0, 10).is_none()); // y out of bounds
        assert!(buf.get(100, 100).is_none());
    }

    #[test]
    fn test_get_returns_some_for_valid() {
        let buf = Buffer::new(10, 10);
        assert!(buf.get(0, 0).is_some());
        assert!(buf.get(9, 9).is_some());
    }

    // --- Scissor stack ---

    #[test]
    fn test_scissor_clips_writes() {
        let mut buf = Buffer::new(20, 20);
        buf.push_scissor(Rect::new(5, 5, 10, 10));

        // Write inside scissor - should succeed
        buf.set(7, 7, Cell::char('A'));
        assert_eq!(buf.get(7, 7).unwrap().content.to_char(), Some('A'));

        // Write outside scissor - should be ignored
        buf.set(0, 0, Cell::char('B'));
        assert_eq!(*buf.get(0, 0).unwrap(), Cell::default());
    }

    #[test]
    fn test_scissor_intersection() {
        let mut buf = Buffer::new(100, 100);
        buf.push_scissor(Rect::new(10, 10, 50, 50)); // 10..60
        buf.push_scissor(Rect::new(30, 30, 50, 50)); // 30..80, but intersection is 30..60

        let scissor = buf.current_scissor();
        assert_eq!(scissor.x, 30);
        assert_eq!(scissor.y, 30);
        assert_eq!(scissor.width, 30); // min(60, 80) - 30 = 30
        assert_eq!(scissor.height, 30);
    }

    #[test]
    fn test_pop_scissor_preserves_base() {
        let mut buf = Buffer::new(10, 10);
        buf.pop_scissor(); // Should be no-op
        buf.pop_scissor();
        buf.pop_scissor();
        assert_eq!(buf.current_scissor(), Rect::new(0, 0, 10, 10));
    }

    // --- Opacity stack ---

    #[test]
    fn test_opacity_multiplies() {
        let mut buf = Buffer::new(10, 10);
        assert_eq!(buf.current_opacity(), 1.0);

        buf.push_opacity(0.5);
        assert_eq!(buf.current_opacity(), 0.5);

        buf.push_opacity(0.5);
        assert_eq!(buf.current_opacity(), 0.25);

        buf.pop_opacity();
        assert_eq!(buf.current_opacity(), 0.5);
    }

    #[test]
    fn test_opacity_clamps() {
        let mut buf = Buffer::new(10, 10);
        buf.push_opacity(2.0); // Clamped to 1.0
        assert_eq!(buf.current_opacity(), 1.0);

        buf.push_opacity(-0.5); // Clamped to 0.0
        assert_eq!(buf.current_opacity(), 0.0);
    }

    // --- Wide characters ---

    #[test]
    fn test_wide_char_sets_continuation() {
        let mut buf = Buffer::new(10, 1);
        let wide_cell = Cell::new("中", Style::default()); // Width 2
        buf.set(0, 0, wide_cell);

        assert!(buf.get(1, 0).unwrap().is_continuation());
    }

    #[test]
    fn test_wide_char_at_edge() {
        let mut buf = Buffer::new(5, 1);
        let wide_cell = Cell::new("中", Style::default());
        buf.set(4, 0, wide_cell); // At edge, no room for continuation

        // Should still set the cell, continuation would be OOB
        assert!(!buf.get(4, 0).unwrap().is_continuation());
    }

    // --- set_string ---

    #[test]
    fn test_set_string() {
        let mut buf = Buffer::new(20, 1);
        let end_x = buf.set_string(0, 0, "Hello", Style::default());
        assert_eq!(end_x, 5);
        assert_eq!(buf.get(0, 0).unwrap().content.to_char(), Some('H'));
        assert_eq!(buf.get(4, 0).unwrap().content.to_char(), Some('o'));
    }

    #[test]
    fn test_set_string_with_wide_chars() {
        let mut buf = Buffer::new(20, 1);
        let end_x = buf.set_string(0, 0, "Hi世界", Style::default());
        assert_eq!(end_x, 6); // 2 ASCII + 2*2 wide chars
    }

    // --- Invariants ---

    #[test]
    fn test_invariant_cells_len() {
        for w in [1, 10, 80, 255] {
            for h in [1, 10, 24, 255] {
                let buf = Buffer::new(w, h);
                assert_eq!(buf.cells().len(), (w as usize) * (h as usize));
            }
        }
    }
}
